import{_ as a,o as r,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const y=JSON.parse('{"title":"162. Accrued Days Off","description":"","frontmatter":{"title":"162. Accrued Days Off","eba":"Mental Health Services 2024-2028","topics":["leave","annual-leave","wages"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/162-accrued-days-off.md","filePath":"ebas/mental-health/support-services/preliminary/162-accrued-days-off.md"}'),s={name:"ebas/mental-health/support-services/preliminary/162-accrued-days-off.md"};function n(c,e,l,d,i,f){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="_162-accrued-days-off" tabindex="-1">162. Accrued Days Off <a class="header-anchor" href="#_162-accrued-days-off" aria-label="Permalink to &quot;162. Accrued Days Off&quot;">​</a></h1><p><strong>162.1</strong> Where the system of working provides for accrued days off, Employees shall work an additional 0.4 hours per day, or 2 hours per week, to facilitate one accrued day off (ADO) after every 4 weeks of service.</p><p><strong>162.2</strong> The maximum ADOs shall be 13 in any calendar year, provided that one (1) ADO shall be taken in conjunction with a period of annual leave, for which no additional payment is to be made.</p><p><strong>162.3</strong> Accrued days off are to be taken as single days on a rostered basis (i.e. 1 ADO in each 28-day cycle), as agreed between the Employer and Employee provided that the Employer and Employee may mutually agree to defer a rostered ADO for a maximum of one month, but only in exceptional circumstances.</p><p><strong>162.4</strong> Taking of ADOs Wherever practicable, an ADO will be on the date requested by the Employee.</p><p><strong>162.5</strong> Public Holidays and Accrued Days Off Where an Employee&#39;s accrued day off falls on a public holiday, another day shall be determined by the Employer to be taken in lieu thereof, within the same 4-week cycle (where practicable).</p>',6)])])}const h=a(s,[["render",n]]);export{y as __pageData,h as default};
